// GET - Fetch all users with profiles
// GET - Fetch all users with profiles & auth status
export async function GET() {
    const cookieStore = await cookies()

    // 1. Check if user is admin using RLS/Middleware protection
    const supabase = createServerClient(
        'http://127.0.0.1:54321', // process.env.NEXT_PUBLIC_SUPABASE_URL!
        'sb_publishable_ACJWlzQHlZjBrEguHvfOxg_3BJgxAaH', // process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
        {
            cookies: {
                getAll() {
                    return cookieStore.getAll()
                },
                setAll() { },
            },
        }
    )

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) {
        return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const { data: currentProfile } = await supabase
        .from('profiles')
        .select('role')
        .eq('id', user.id)
        .single()

    if (!['admin', 'chef', 'foh'].includes(currentProfile?.role || '')) {
        return NextResponse.json({ error: 'Forbidden' }, { status: 403 })
    }

    // 2. Check for Service Role Key
    if (!process.env.SUPABASE_SERVICE_ROLE_KEY) {
        return NextResponse.json({
            error: 'Database config missing. Please add SUPABASE_SERVICE_ROLE_KEY to .env.local'
        }, { status: 500 })
    }

    // 3. Use service role to get Auth Users (for email status) AND Profiles
    const serviceClient = createClient(
        'http://127.0.0.1:54321', // process.env.NEXT_PUBLIC_SUPABASE_URL!
        'sb_secret_N7UND0UgjKTVK-Uodkm0Hg_xSvEMPvz' // process.env.SUPABASE_SERVICE_ROLE_KEY!
    )

    // Fetch Auth Users (gives us email_confirmed_at)
    const { data: { users: authUsers }, error: authError } = await serviceClient.auth.admin.listUsers({
        perPage: 1000
    })

    if (authError) {
        return NextResponse.json({ error: 'Auth Error: ' + authError.message }, { status: 500 })
    }

    // Fetch Profiles (gives us roles)
    const { data: profiles, error: dbError } = await serviceClient
        .from('profiles')
        .select('id, role, restaurant_name, created_at')

    if (dbError) {
        return NextResponse.json({ error: 'DB Error: ' + dbError.message }, { status: 500 })
    }

    // 4. Merge Data
    const combinedUsers = authUsers.map(authUser => {
        const profile = profiles?.find(p => p.id === authUser.id)
        return {
            id: authUser.id,
            email: authUser.email,
            email_confirmed_at: authUser.email_confirmed_at,
            last_sign_in_at: authUser.last_sign_in_at,
            role: profile?.role || 'foh', // Fallback role
            restaurant_name: profile?.restaurant_name,
            created_at: authUser.created_at
        }
    })

    // Sort by created most recent
    combinedUsers.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())

    return NextResponse.json({ users: combinedUsers })
}

// PATCH - Update user role OR confirm email
export async function PATCH(request: Request) {
    const cookieStore = await cookies()
    const supabase = createServerClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
        {
            cookies: { getAll: () => cookieStore.getAll(), setAll: () => { } }
        }
    )

    // Admin Check
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

    const { data: currentProfile } = await supabase.from('profiles').select('role').eq('id', user.id).single()
    if (currentProfile?.role !== 'admin') return NextResponse.json({ error: 'Forbidden' }, { status: 403 })

    if (!process.env.SUPABASE_SERVICE_ROLE_KEY) {
        return NextResponse.json({ error: 'Missing Service Role Key' }, { status: 500 })
    }

    const serviceClient = createClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.SUPABASE_SERVICE_ROLE_KEY!
    )

    const body = await request.json()
    const { userId, action, value } = body

    try {
        if (action === 'update_role') {
            // Update Role in DB
            const { error } = await serviceClient
                .from('profiles')
                .update({ role: value })
                .eq('id', userId)
            if (error) throw error

            return NextResponse.json({ success: true, message: 'Role updated' })
        }

        else if (action === 'confirm_email') {
            // Manually confirm email via Auth Admin
            const { error } = await serviceClient.auth.admin.updateUserById(
                userId,
                { email_confirm: true }
            )
            if (error) throw error

            return NextResponse.json({ success: true, message: 'User confirmed' })
        }

        return NextResponse.json({ error: 'Invalid action' }, { status: 400 })

    } catch (err: any) {
        return NextResponse.json({ error: err.message }, { status: 500 })
    }
}

import { createClient } from '@/lib/supabase/server'
import { NextResponse } from 'next/server'

// "The Oracle" - Predictive Inventory
// Logic:
// 1. Get sales from last 30 days
// 2. Break down sales into ingredient usage
// 3. Calculate Daily Average Usage (DAU)
// 4. Set Par Level = DAU * 3 (3 days of safety stock)

export async function GET() {
    try {
        const supabase = await createClient()

        // 1. Get date 30 days ago
        const thirtyDaysAgo = new Date()
        thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30)

        // 2. Fetch Sales Logs
        const { data: sales, error: salesError } = await supabase
            .from('sales_logs')
            .select(`
                quantity_sold,
                recipe:recipes (
                    id,
                    recipe_items (
                        quantity_needed,
                        ingredient_id
                    )
                )
            `)
            .gte('sale_date', thirtyDaysAgo.toISOString())

        if (salesError) throw salesError

        // 3. Aggregate Usage per Ingredient
        const ingredientUsage: Record<string, number> = {}

        sales?.forEach((log: any) => {
            const recipe = log.recipe
            if (recipe && recipe.recipe_items) {
                recipe.recipe_items.forEach((item: any) => {
                    const totalQtyUsed = item.quantity_needed * log.quantity_sold
                    if (!ingredientUsage[item.ingredient_id]) {
                        ingredientUsage[item.ingredient_id] = 0
                    }
                    ingredientUsage[item.ingredient_id] += totalQtyUsed
                })
            }
        })

        // 4. Calculate New Par Levels
        const updates = []
        for (const [ingredientId, totalUsage] of Object.entries(ingredientUsage)) {
            const dailyAverage = totalUsage / 30
            // Safety Stock = 3 days of usage
            const newParLevel = Math.ceil(dailyAverage * 3)

            updates.push({
                id: ingredientId,
                par_level: newParLevel
            })

            // Update Database
            await supabase
                .from('ingredients')
                .update({ par_level: newParLevel })
                .eq('id', ingredientId)
        }

        return NextResponse.json({
            success: true,
            message: `Oracle updated par levels for ${updates.length} ingredients`,
            updates
        })

    } catch (error: any) {
        return NextResponse.json({ success: false, error: error.message }, { status: 500 })
    }
}

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@/lib/supabase/server'

const QB_API_URL = process.env.QUICKBOOKS_ENVIRONMENT === 'production'
    ? 'https://quickbooks.api.intuit.com'
    : 'https://sandbox-quickbooks.api.intuit.com'

export async function POST(request: NextRequest) {
    const supabase = await createClient()

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) {
        return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const { data: connection } = await supabase
        .from('integrations')
        .select('*')
        .eq('user_id', user.id)
        .eq('provider', 'quickbooks')
        .single()

    if (!connection) {
        return NextResponse.json({ error: 'Not connected to QuickBooks' }, { status: 400 })
    }

    try {
        // Fetch items from QuickBooks
        const itemsResponse = await fetch(
            `${QB_API_URL}/v3/company/${connection.merchant_id}/query?query=SELECT * FROM Item`,
            {
                headers: {
                    'Authorization': `Bearer ${connection.access_token}`,
                    'Accept': 'application/json',
                },
            }
        )

        const itemsData = await itemsResponse.json()

        if (!itemsResponse.ok) {
            return NextResponse.json({ error: 'Failed to fetch items' }, { status: 500 })
        }

        const items = itemsData.QueryResponse?.Item || []
        let imported = 0

        for (const item of items) {
            const ingredient = {
                user_id: user.id,
                name: item.Name,
                purchase_price: item.PurchaseCost || item.UnitPrice || 0,
                purchase_unit: 'unit',
                current_stock: item.QtyOnHand || 0,
                conversion_ratio: 1,
                source: 'quickbooks',
                external_id: item.Id,
            }

            const { error } = await supabase
                .from('ingredients')
                .upsert(ingredient, {
                    onConflict: 'user_id,external_id',
                    ignoreDuplicates: false
                })

            if (!error) imported++
        }

        await supabase
            .from('integrations')
            .update({ last_sync: new Date().toISOString() })
            .eq('user_id', user.id)
            .eq('provider', 'quickbooks')

        return NextResponse.json({ success: true, itemCount: imported })
    } catch (error) {
        console.error('QuickBooks sync error:', error)
        return NextResponse.json({ error: 'Sync failed' }, { status: 500 })
    }
}

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@/lib/supabase/server'

const SQUARE_API_URL = process.env.SQUARE_ENVIRONMENT === 'production'
    ? 'https://connect.squareup.com'
    : 'https://connect.squareupsandbox.com'

export async function POST(request: NextRequest) {
    const supabase = await createClient()

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) {
        return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    // Get the Square connection
    const { data: connection, error: connError } = await supabase
        .from('integrations')
        .select('*')
        .eq('user_id', user.id)
        .eq('provider', 'square')
        .single()

    if (connError || !connection) {
        return NextResponse.json({ error: 'Not connected to Square' }, { status: 400 })
    }

    try {
        // Fetch catalog items from Square
        const catalogResponse = await fetch(`${SQUARE_API_URL}/v2/catalog/list?types=ITEM`, {
            headers: {
                'Authorization': `Bearer ${connection.access_token}`,
                'Square-Version': '2024-01-18',
                'Content-Type': 'application/json',
            },
        })

        const catalogData = await catalogResponse.json()

        if (!catalogResponse.ok) {
            console.error('Square API error:', catalogData)
            return NextResponse.json({ error: 'Failed to fetch catalog' }, { status: 500 })
        }

        const items = catalogData.objects || []
        let imported = 0

        // Convert Square items to Mise ingredients
        for (const item of items) {
            if (item.type !== 'ITEM') continue

            const itemData = item.item_data
            const variation = itemData.variations?.[0]?.item_variation_data
            const price = variation?.price_money?.amount || 0

            const ingredient = {
                user_id: user.id,
                name: itemData.name,
                purchase_price: price / 100, // Square stores in cents
                purchase_unit: 'unit',
                current_stock: 0,
                conversion_ratio: 1,
                source: 'square',
                external_id: item.id,
            }

            // Upsert to avoid duplicates
            const { error: insertError } = await supabase
                .from('ingredients')
                .upsert(ingredient, {
                    onConflict: 'user_id,external_id',
                    ignoreDuplicates: false
                })

            if (!insertError) imported++
        }

        // Update last sync time
        await supabase
            .from('integrations')
            .update({ last_sync: new Date().toISOString() })
            .eq('user_id', user.id)
            .eq('provider', 'square')

        return NextResponse.json({
            success: true,
            itemCount: imported,
            total: items.length
        })
    } catch (error) {
        console.error('Square sync error:', error)
        return NextResponse.json({ error: 'Sync failed' }, { status: 500 })
    }
}

