        const menusResponse = await fetch(`${TOAST_API_URL}/menus/v2/menus`, {
            headers: {
                'Authorization': `Bearer ${connection.access_token}`,
                'Toast-Restaurant-External-ID': connection.merchant_id || '',
            },
        })

        const menusData = await menusResponse.json()

        if (!menusResponse.ok) {
            return NextResponse.json({ error: 'Failed to fetch menus' }, { status: 500 })
        }

        let imported = 0

        // Process menu items
        for (const menu of menusData) {
            for (const group of menu.groups || []) {
                for (const item of group.items || []) {
                    const ingredient = {
                        user_id: user.id,
                        name: item.name,
                        purchase_price: (item.price || 0) / 100,
                        purchase_unit: 'unit',
                        current_stock: 0,
                        conversion_ratio: 1,
                        source: 'toast',
                        external_id: item.guid,
                    }

                    const { error } = await supabase
                        .from('ingredients')
                        .upsert(ingredient, {
                            onConflict: 'user_id,external_id',
                            ignoreDuplicates: false
                        })

                    if (!error) imported++
                }
            }
        }

        await supabase
            .from('integrations')
            .update({ last_sync: new Date().toISOString() })
            .eq('user_id', user.id)
            .eq('provider', 'toast')

        return NextResponse.json({ success: true, itemCount: imported })
    } catch (error) {
        console.error('Toast sync error:', error)
        return NextResponse.json({ error: 'Sync failed' }, { status: 500 })
    }
}

import { createClient } from '@/lib/supabase/server'
import { NextRequest, NextResponse } from 'next/server'

/**
 * POS Order Webhook
 * 
 * When a dish is sold via POS, this endpoint depletes the ingredient stock.
 * 
 * POST /api/webhooks/front-desk-order
 * Body: { menu_item_id: string, qty: number, api_key?: string }
 */
export async function POST(request: NextRequest) {
    try {
        const body = await request.json()
        const { menu_item_id, qty = 1, api_key, user_id } = body

        // Validate required fields
        if (!menu_item_id) {
            return NextResponse.json(
                { success: false, error: 'menu_item_id is required' },
                { status: 400 }
            )
        }

        if (!user_id) {
            return NextResponse.json(
                { success: false, error: 'user_id is required' },
                { status: 400 }
            )
        }

        // TODO: Validate API key for security
        // For now, we trust the user_id provided
        // In production, implement proper API key validation

        const supabase = await createClient()

        // Call the atomic POS order function
        const { data, error } = await supabase.rpc('process_pos_order', {
            p_user_id: user_id,
            p_recipe_id: menu_item_id,
            p_quantity: qty
        })

        if (error) {
            console.error('POS order error:', error)
            return NextResponse.json(
                { success: false, error: error.message },
                { status: 500 }
            )
        }

        return NextResponse.json(data)
    } catch (error) {
        console.error('POS webhook error:', error)
        return NextResponse.json(
            { success: false, error: 'Internal server error' },
            { status: 500 }
        )
    }
}

