export function KitchenDisplay({ initialOrders }: KdsProps) {
    const supabase = createClient()
    const [orders, setOrders] = useState(initialOrders)
    const [viewMode, setViewMode] = useState<'active' | 'history'>('active')
    const [historyOrders, setHistoryOrders] = useState<any[]>([])
    const [currentTime, setCurrentTime] = useState(new Date())
    const [exitingOrders, setExitingOrders] = useState<Set<string>>(new Set())
    const audioRef = useRef<HTMLAudioElement | null>(null)

    // Clock update
    useEffect(() => {
        const interval = setInterval(() => setCurrentTime(new Date()), 1000)
        return () => clearInterval(interval)
    }, [])

    // Initialize audio
    useEffect(() => {
        audioRef.current = new Audio('/sounds/ping.mp3')
        audioRef.current.volume = 0.5
    }, [])

    // Real-time subscription
    useEffect(() => {
        const channel = supabase
            .channel('kds_realtime')
            .on(
                'postgres_changes',
                { event: 'INSERT', schema: 'public', table: 'orders' },
                async (payload) => {
                    // Play sound on new order
                    if (payload.new.status === 'paid') {
                        audioRef.current?.play().catch(() => { })
                        toast.success('New Order!', { description: `Table ${payload.new.table_or_room || 'Walk-in'}` })
                    }
                    // Refetch to get full order with items
                    await refetchOrders()
                }
            )
            .on(
                'postgres_changes',
                { event: 'UPDATE', schema: 'public', table: 'orders' },
                async (payload) => {
                    // If update happens, refreshes local state to stay in sync
                    // Ideally we merge payload, but refetch is safer for now
                    await refetchOrders()
                }
            )
            .subscribe()

        return () => {
            supabase.removeChannel(channel)
        }
    }, [supabase])

    // Load history when tab is switched
    useEffect(() => {
        if (viewMode === 'history') {
            fetchHistory()
        }
    }, [viewMode])

    const fetchHistory = async () => {
        const { data } = await supabase
            .from('orders')
            .select('*, order_items(*, recipe:recipes(name))')
            .eq('status', 'paid')
            .eq('preparation_status', 'delivered')
            .order('created_at', { ascending: false })
            .limit(50)

        if (data) setHistoryOrders(data)
    }

    const refetchOrders = async () => {
        const { data } = await supabase
            .from('orders')
            .select('*, order_items(*, recipe:recipes(name))')
            .eq('status', 'paid')
            .neq('preparation_status', 'delivered')
            .order('created_at', { ascending: true })

        if (data) setOrders(data)
    }

    const updateOrderStatus = async (orderId: string, currentStatus: string) => {
        const config = statusConfig[currentStatus as keyof typeof statusConfig]
        if (!config?.next) return

        // OPTIMISTIC UPDATE: Update local state immediately
        const nextStatus = config.next

        let shouldRemove = false
        if (nextStatus === 'delivered') {
            shouldRemove = true
            setExitingOrders(prev => new Set(prev).add(orderId))
            // Wait for animation before removing from DOM
            await new Promise(resolve => setTimeout(resolve, 300))
        }

        // Apply optimistic change
        setOrders(prev => {
            if (shouldRemove) {
                return prev.filter(o => o.id !== orderId)
            }
            return prev.map(o => o.id === orderId ? { ...o, preparation_status: nextStatus } : o)
        })

        // Perform actual DB update
        const updatePayload: any = { preparation_status: nextStatus }
        if (nextStatus === 'delivered') {
            updatePayload.tracking_pin = null
        }

        const { error } = await supabase
            .from('orders')
            .update(updatePayload)
            .eq('id', orderId)

        if (error) {
            toast.error('Failed to update status')
            // Revert on error (re-fetch)
            refetchOrders()
            // Reset exit state if needed
            setExitingOrders(prev => {
                const next = new Set(prev)
                next.delete(orderId)
                return next
            })
        } else {
            const msg = nextStatus === 'delivered' ? 'Order Delivered!' : `Status: ${nextStatus}`
            toast.success(msg)
            // If delivered, refresh history to show it immediately if user switches
            if (nextStatus === 'delivered') fetchHistory()
        }
    }

    const displayedOrders = viewMode === 'active' ? orders : historyOrders

    // Empty state
    if (orders.length === 0 && viewMode === 'active') {
        return (
            <div className="space-y-6 relative">
                {/* Ambient Background Glows */}
                <div className="absolute top-0 right-0 w-[600px] h-[600px] bg-primary/5 rounded-full blur-[140px] -z-10" />

                {/* View Toggle */}
                <div className="flex items-center gap-4">
                    <div className="flex bg-card rounded-lg p-1">
                        <button
                            onClick={() => setViewMode('active')}
                            className={cn("px-4 py-2 rounded-md text-sm font-bold transition-all bg-secondary text-foreground shadow")}
                        >
                            Active
                        </button>
                        <button
                            onClick={() => setViewMode('history')}
                            className={cn("px-4 py-2 rounded-md text-sm font-bold transition-all text-muted-foreground hover:text-foreground")}
                        >
                            Past Orders
                        </button>
                    </div>
                </div>

                <div className="min-h-[50vh] flex flex-col items-center justify-center">
                    <div className="text-center">
                        <div className="w-24 h-24 rounded-full bg-primary/10 flex items-center justify-center mx-auto mb-6">
                            <ChefHat className="w-12 h-12 text-primary" />
                        </div>
                        <h2 className="text-2xl font-bold text-foreground mb-2">Service is Clear</h2>
                        <p className="text-muted-foreground">All caught up. No active orders.</p>
                    </div>
                </div>
            </div>
        )
    }

    return (
        <div className="space-y-6">
            {/* Controls Bar */}
            <div className="flex items-center gap-4">
                {/* View Toggle */}
                <div className="flex bg-card rounded-lg p-1">
                    <button
                        onClick={() => setViewMode('active')}
                        className={cn("px-4 py-2 rounded-md text-sm font-bold transition-all", viewMode === 'active' ? "bg-secondary text-foreground shadow" : "text-muted-foreground hover:text-foreground")}
                    >
                        Active
                    </button>
                    <button
                        onClick={() => setViewMode('history')}
                        className={cn("px-4 py-2 rounded-md text-sm font-bold transition-all", viewMode === 'history' ? "bg-secondary text-foreground shadow" : "text-muted-foreground hover:text-foreground")}
                    >
                        History
                    </button>
                </div>

                <div className="flex items-center gap-2 text-muted-foreground bg-card px-4 py-2 rounded-lg ml-auto md:ml-0">
                    <Clock className="w-4 h-4" />
                    <span className="font-mono text-lg">
                        {currentTime.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
                    </span>
                </div>

                <button
                    onClick={() => audioRef.current?.play().catch(() => { })}
                    className="p-2 text-muted-foreground hover:text-foreground transition hidden md:block"
                    title="Test Sound"
                >
                    <Volume2 className="w-5 h-5" />
                </button>
            </div>

            {/* Order Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {displayedOrders.map((order) => {
                    const status = order.preparation_status as string
                    const config = statusConfig[status as keyof typeof statusConfig]
                    const isExiting = exitingOrders.has(order.id)

                    // For history items (delivered), we can use a simpler card style or same style
                    // If status is 'delivered', we need config for it
                    if (status === 'delivered') {
                        return (
                            <div key={order.id} className="bg-card/50 border border-border rounded-2xl p-5 opacity-75 grayscale hover:grayscale-0 transition-all">
                                <div className="flex justify-between mb-4">
                                    <span className="font-mono text-xs text-muted-foreground">#{order.id.slice(0, 8)}</span>
                                    <span className="bg-secondary text-muted-foreground px-2 py-1 rounded text-xs uppercase font-bold">Delivered</span>
                                </div>
                                <h3 className="text-lg font-bold text-foreground mb-2">
                                    {order.table_or_room ? `Room ${order.table_or_room}` : 'Walk-in'}
                                </h3>
                                <ul className="space-y-2 mb-4">
                                    {order.order_items?.map((item: any) => (
                                        <li key={item.id} className="flex gap-2 text-sm text-muted-foreground">
                                            <span className="font-bold text-foreground">{item.quantity}x</span>
                                            {item.recipe?.name || item.recipe_name}
                                        </li>
                                    ))}
                                </ul>
                                <div className="text-xs text-muted-foreground flex items-center gap-2">
                                    <CheckSquare className="w-3 h-3" />
                                    <span>Completed {formatDistanceToNow(new Date(order.created_at), { addSuffix: true })}</span>
                                </div>
                            </div>
                        )
                    }

                    if (!config) return null

                    return (
                        <div
                            key={order.id}
                            className={cn(
                                "bg-card border-2 rounded-2xl overflow-hidden flex flex-col transition-all duration-300",
                                config.border,
                                config.bg,
                                isExiting && "opacity-0 scale-95 translate-y-4"
                            )}
                        >
                            {/* Card Header */}
                            <div className="p-5 border-b border-border">
                                <div className="flex items-center justify-between mb-3">
                                    <span className="text-xs font-mono text-muted-foreground">#{order.id.slice(0, 8)}</span>
                                    <span className={cn("text-xs font-bold uppercase px-2.5 py-1 rounded-full border", config.badge)}>
                                        {status}
                                    </span>
                                </div>
                                <div className="flex items-center justify-between">
                                    <h3 className="text-xl font-bold text-foreground flex items-center gap-2">
                                        <Utensils className="w-5 h-5 text-muted-foreground" />
                                        {order.table_or_room ? `Room ${order.table_or_room}` : 'Walk-in'}
                                    </h3>
                                    <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                                        <Timer className="w-3.5 h-3.5" />
                                        {formatDistanceToNow(new Date(order.created_at), { addSuffix: true })}
                                    </div>
                                </div>
                            </div>

                            {/* Card Body - Order Items */}
                            <div className="p-5 flex-1">
                                <ul className="space-y-3">
                                    {order.order_items?.map((item: any) => (
                                        <li key={item.id} className="flex items-start gap-3">
                                            <span className="w-7 h-7 rounded-lg bg-secondary flex items-center justify-center text-sm font-bold text-foreground shrink-0">
                                                {item.quantity}
                                            </span>
                                            <span className="text-foreground font-medium leading-tight pt-1">
                                                {item.recipe?.name || item.recipe_name || 'Unknown Item'}
                                            </span>
                                        </li>
                                    ))}
                                </ul>
                            </div>

                            {/* Card Footer - Action Button */}
                            <div className="p-4 bg-sidebar/30">
                                <div className="space-y-2">
                                    <button
                                        onClick={() => updateOrderStatus(order.id, status)}
                                        className={cn(
                                            "w-full h-14 rounded-xl text-foreground font-bold text-lg transition-all active:scale-[0.98]",
                                            config.button
                                        )}
                                    >
                                        {config.buttonText}
                                    </button>

                                    <div className="flex gap-2">
                                        <div className="flex-1 h-12 bg-white/5 rounded-2xl border border-white/5 flex items-center justify-center gap-3 px-4 shadow-inner">
                                            <span className="text-[10px] font-black text-foreground/30 uppercase tracking-[0.2em]">PIN</span>
                                            <span className="text-sm font-black text-primary font-mono tracking-widest">{order.tracking_pin || '----'}</span>
                                        </div>
                                        <a
                                            href={`/guest/${order.table_or_room}?pin=${order.tracking_pin}`}
                                            target="_blank"
                                            rel="noopener noreferrer"
                                            className="flex-1 h-12 bg-white/5 hover:bg-white/10 rounded-2xl border border-white/5 flex items-center justify-center gap-2 transition-all active:scale-95 group"
                                            title="View Guest Tracking / Receipt"
                                        >
                                            <span className="text-[10px] font-black text-foreground uppercase tracking-[0.2em]">SYNC</span>
                                            <ExternalLink className="w-3 h-3 text-foreground/40 group-hover:text-primary transition-colors" />
                                        </a>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )
                })}
            </div>
        </div>
    )
}

'use client'

import { useState } from 'react'
import { format } from 'date-fns'
import { useMutation, useQueryClient } from '@tanstack/react-query'
import { createClient } from '@/lib/supabase/client'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table"
import { History, PackageCheck, Truck, Check } from 'lucide-react'
import { toast } from 'sonner'

interface OrderHistoryItem {
    id: string
    quantity_to_order: number
    status: string
    created_at: string
    vendor_price: number | null
    expected_delivery_date: string | null
    received_date: string | null
    ingredients: {
        name: string
        purchase_unit: string
        purchase_price: number
    } | null
    suppliers: {
        name: string
    } | null
}

interface OrderHistoryProps {
    orders: OrderHistoryItem[]
}

export function OrderHistory({ orders }: OrderHistoryProps) {
    const supabase = createClient()

    const markReceivedMutation = useMutation({
        mutationFn: async (orderId: string) => {
            const { error } = await supabase
                .from('shopping_list')
                .update({
                    status: 'received',
                    received_date: new Date().toISOString().split('T')[0]
                })
                .eq('id', orderId)

            if (error) throw error
        },
        onSuccess: () => {
            toast.success('Order marked as received!')
            // Refresh page to update list
            window.location.reload()
        },
        onError: (err) => toast.error(err.message)
    })

    if (orders.length === 0) {
        return (
            <Card className="bg-card border-border">
                <CardContent className="flex flex-col items-center justify-center py-12 text-center">
                    <History className="w-12 h-12 text-muted-foreground mb-4" />
                    <h3 className="text-xl font-bold text-foreground">No Order History</h3>
                    <p className="text-muted-foreground mt-2">You haven't placed any orders yet.</p>
                </CardContent>
            </Card>
        )
    }

    const getStatusBadge = (status: string) => {
        switch (status) {
            case 'pending':
                return <Badge className="bg-amber-500/10 text-amber-500 border-amber-500/20">Pending</Badge>
            case 'ordered':
                return <Badge className="bg-blue-500/10 text-blue-500 border-blue-500/20">Ordered</Badge>
            case 'received':
                return <Badge className="bg-primary/10 text-primary border-primary/20">Received</Badge>
            default:
                return <Badge variant="outline">{status}</Badge>
        }
    }

    return (
        <Card className="bg-card border-border">
            <CardHeader>
                <CardTitle className="text-foreground flex items-center gap-2">
                    <History className="w-5 h-5 text-muted-foreground" />
                    Order History
                </CardTitle>
            </CardHeader>
            <CardContent>
                <Table>
                    <TableHeader>
                        <TableRow className="border-border hover:bg-transparent">
                            <TableHead className="text-muted-foreground">Date</TableHead>
                            <TableHead className="text-muted-foreground">Ingredient</TableHead>
                            <TableHead className="text-muted-foreground">Vendor</TableHead>
                            <TableHead className="text-muted-foreground">Qty</TableHead>
                            <TableHead className="text-muted-foreground">Cost</TableHead>
                            <TableHead className="text-muted-foreground">Expected</TableHead>
                            <TableHead className="text-muted-foreground">Status</TableHead>
                            <TableHead className="w-[100px]"></TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {orders.map((order) => {
                            const cost = order.vendor_price
                                ? order.quantity_to_order * order.vendor_price
                                : (order.quantity_to_order || 0) * (order.ingredients?.purchase_price || 0)

                            return (
                                <TableRow key={order.id} className="border-border hover:bg-secondary/50">
                                    <TableCell className="text-foreground font-medium whitespace-nowrap">
                                        {format(new Date(order.created_at), 'MMM d')}
                                    </TableCell>
                                    <TableCell className="text-foreground">
                                        {order.ingredients?.name || 'Unknown Item'}
                                    </TableCell>
                                    <TableCell>
                                        <Badge variant="outline" className="text-xs border-border text-muted-foreground">
                                            {order.suppliers?.name || 'Direct'}
                                        </Badge>
                                    </TableCell>
                                    <TableCell className="text-foreground">
                                        {order.quantity_to_order} {order.ingredients?.purchase_unit}
                                    </TableCell>
                                    <TableCell className="text-foreground">
                                        ${cost.toFixed(2)}
                                    </TableCell>
                                    <TableCell className="text-muted-foreground text-sm">
                                        {order.expected_delivery_date
                                            ? format(new Date(order.expected_delivery_date), 'MMM d')
                                            : <span className="text-muted-foreground">—</span>
                                        }
                                    </TableCell>
                                    <TableCell>
                                        {getStatusBadge(order.status)}
                                    </TableCell>
                                    <TableCell>
                                        {order.status === 'ordered' && (
                                            <Button
                                                size="sm"
                                                variant="ghost"
                                                className="text-primary hover:text-primary hover:bg-primary/10"
                                                onClick={() => markReceivedMutation.mutate(order.id)}
                                                disabled={markReceivedMutation.isPending}
                                            >
                                                <Check className="w-4 h-4 mr-1" />
                                                Receive
                                            </Button>
                                        )}
                                        {order.status === 'received' && order.received_date && (
                                            <span className="text-xs text-muted-foreground">
                                                {format(new Date(order.received_date), 'MMM d')}
                                            </span>
                                        )}
                                    </TableCell>
                                </TableRow>
                            )
                        })}
                    </TableBody>
                </Table>
            </CardContent>
        </Card>
    )
}

'use client'

import { useState, useMemo, useEffect, useRef } from 'react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'
import { useMutation } from '@tanstack/react-query'
import { createClient } from '@/lib/supabase/client'
import { Send, AlertTriangle, CheckCircle2, RefreshCw } from 'lucide-react'
import { toast } from 'sonner'

import { Input } from '@/components/ui/input'
import { Button } from '@/components/ui/button'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table"
import { Dialog, DialogContent } from '@/components/ui/dialog'

import { type Ingredient, type Supplier, type VendorProduct } from '@/lib/types/database'
import { VendorPriceManager } from '@/components/vendors/vendor-price-manager'

interface SmartOrderListProps {
    ingredients: Ingredient[]
    vendors: Supplier[]
    vendorProducts: VendorProduct[]
    activeOrders: any[]
}

export function SmartOrderList({ ingredients, vendors, vendorProducts, activeOrders }: SmartOrderListProps) {
    const router = useRouter()
    const supabase = createClient()

    // State for vendor price management dialog
    const [managePricesItem, setManagePricesItem] = useState<any | null>(null)

    // 1. Identify items below par (or default threshold of 5)
    const lowStockItems = useMemo(() => {
        return ingredients.filter(i => {
            const effectivePar = i.par_level || 5 // Match the "Red Pulse" threshold from Pantry view
            return (i.current_stock ?? 0) < effectivePar
        })
    }, [ingredients])

    // 4. Manually added items (IDs)
    const [addedIds, setAddedIds] = useState<string[]>([])
    // 5. Manually removed items (IDs)
    const [removedIds, setRemovedIds] = useState<string[]>([])
    // 6. Search state for adding items
    const [itemSearch, setItemSearch] = useState('')
    const [isAddOpen, setIsAddOpen] = useState(false)

    // Ref for click-outside detection
    const popupRef = useRef<HTMLDivElement>(null)

    // Click outside to close popup
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (popupRef.current && !popupRef.current.contains(event.target as Node)) {
                setIsAddOpen(false)
                setItemSearch('')
            }
        }

        if (isAddOpen) {
            document.addEventListener('mousedown', handleClickOutside)
        }

        return () => {
            document.removeEventListener('mousedown', handleClickOutside)
        }
    }, [isAddOpen])

    // Compute the final list of items to display
    const visibleItems = useMemo(() => {
        // Start with ingredients that are either low stock OR manually added
        const candidates = ingredients.filter(i => {
            // Check if already ordered
            const isOrdered = activeOrders.some(o =>
                o.ingredient_id === i.id &&
                (o.status === 'ordered' || o.status === 'pending')
            )
            if (isOrdered) return false

            const isLow = (i.par_level || 5) > (i.current_stock ?? 0)
            const isAdded = addedIds.includes(i.id)
            return isLow || isAdded
        })

        // Filter out removed items
        return candidates.filter(i => !removedIds.includes(i.id))
    }, [ingredients, addedIds, removedIds, activeOrders])

    // 2. State for order quantities (default to par - stock)
    const [orderQuantities, setOrderQuantities] = useState<Record<string, number>>(() => {
        const initial: Record<string, number> = {}
        const initialLow = ingredients.filter(i => (i.par_level || 5) > (i.current_stock ?? 0))
        initialLow.forEach(i => {
            const effectivePar = i.par_level || 5
            initial[i.id] = Math.max(0, effectivePar - (i.current_stock ?? 0))
        })
        return initial
    })

    // 3. State for selected vendor per ingredient
    const [selectedVendors, setSelectedVendors] = useState<Record<string, { vendorId: string; vendorName: string; price: number }>>(() => {
        const initial: Record<string, { vendorId: string; vendorName: string; price: number }> = {}
        // Auto-select the cheapest vendor for each low stock item
        const initialLow = ingredients.filter(i => (i.par_level || 5) > (i.current_stock ?? 0))
        initialLow.forEach(ingredient => {
            const options = vendorProducts.filter(vp => vp.ingredient_id === ingredient.id)
            if (options.length > 0) {
                // Find cheapest
                const cheapest = options.reduce((min, vp) => vp.vendor_price < min.vendor_price ? vp : min, options[0])
                const vendor = vendors.find(v => v.id === cheapest.vendor_id)
                initial[ingredient.id] = {
                    vendorId: cheapest.vendor_id,
                    vendorName: vendor?.name || 'Unknown',
                    price: cheapest.vendor_price
                }
            } else {
                // Use ingredient's default price if no vendor products
                initial[ingredient.id] = {
                    vendorId: '',
                    vendorName: 'Direct',
                    price: ingredient.purchase_price
                }
            }
        })
        return initial
    })

    // Helper to add item with vendor
    const handleAddItem = (ingredientId: string, vendorId?: string, vendorName?: string, vendorPrice?: number) => {
        if (!addedIds.includes(ingredientId)) {
            setAddedIds(prev => [...prev, ingredientId])
            if (removedIds.includes(ingredientId)) {
                setRemovedIds(prev => prev.filter(id => id !== ingredientId))
            }
            const ingredient = ingredients.find(i => i.id === ingredientId)
            if (ingredient) {
                setOrderQuantities(prev => ({
                    ...prev,
                    [ingredientId]: (ingredient.par_level || 5) > (ingredient.current_stock ?? 0)
                        ? (ingredient.par_level || 5) - (ingredient.current_stock ?? 0)
                        : 1
                }))
                // Set vendor selection
                if (vendorId && vendorName && vendorPrice !== undefined) {
                    setSelectedVendors(prev => ({
                        ...prev,
                        [ingredientId]: { vendorId, vendorName, price: vendorPrice }
                    }))
                } else {
                    // Find cheapest vendor for this ingredient
                    const options = vendorProducts.filter(vp => vp.ingredient_id === ingredientId)
                    if (options.length > 0) {
                        const cheapest = options.reduce((min, vp) => vp.vendor_price < min.vendor_price ? vp : min, options[0])
                        const vendor = vendors.find(v => v.id === cheapest.vendor_id)
                        setSelectedVendors(prev => ({
                            ...prev,
                            [ingredientId]: {
                                vendorId: cheapest.vendor_id,
                                vendorName: vendor?.name || 'Unknown',
                                price: cheapest.vendor_price
                            }
                        }))
                    } else {
                        setSelectedVendors(prev => ({
                            ...prev,
                            [ingredientId]: {
                                vendorId: '',
                                vendorName: 'Direct',
                                price: ingredient.purchase_price
                            }
                        }))
                    }
                }
            }
        }
        setIsAddOpen(false)
        setItemSearch('')
        toast.success('Item added to order')
    }

    const handleRemoveItem = (ingredientId: string) => {
        setRemovedIds(prev => [...prev, ingredientId])
        setOrderQuantities(prev => {
            const next = { ...prev }
            delete next[ingredientId]
            return next
        })
        toast.info('Item removed from order')
    }

    const handleReset = () => {
        setAddedIds([])
        setRemovedIds([])
        // Recalculate defaults
        const initial: Record<string, number> = {}
        lowStockItems.forEach(i => {
            const effectivePar = i.par_level || 5
            initial[i.id] = Math.max(0, effectivePar - (i.current_stock ?? 0))
        })
        setOrderQuantities(initial)
        toast.success('Restored to Smart Suggestions')
    }

    const handleQuantityChange = (id: string, val: string) => {
        setOrderQuantities(prev => ({ ...prev, [id]: parseFloat(val) || 0 }))
    }

    // 3. Mutation to create shopping list items / "Send Order"
    const sendOrderMutation = useMutation({
        mutationFn: async () => {
            // Build items with vendor info
            const itemsToOrder = Object.entries(orderQuantities)
                .filter(([id, qty]) => qty > 0 && visibleItems.find(v => v.id === id))
                .map(([id, qty]) => {
                    const vendorInfo = selectedVendors[id]
                    return {
                        ingredient_id: id,
                        quantity_to_order: qty,
                        vendor_id: vendorInfo?.vendorId || null,
                        vendor_price: vendorInfo?.price || null,
                        status: 'ordered'
                    }
                })

            if (itemsToOrder.length === 0) throw new Error('No items to order')

            const { data: { user } } = await supabase.auth.getUser()
            if (!user) throw new Error('Not authenticated')

            // Insert into shopping_list with vendor info
            const { error } = await supabase
                .from('shopping_list')
                .insert(itemsToOrder.map(item => ({ ...item, user_id: user.id })))

            if (error) throw error

            return itemsToOrder
        },
        onSuccess: (itemsOrdered) => {
            // Group by vendor for confirmation
            const vendorGroups: Record<string, { name: string; items: typeof itemsOrdered; total: number }> = {}

            itemsOrdered.forEach(item => {
                const vendorInfo = selectedVendors[item.ingredient_id]
                const vendorName = vendorInfo?.vendorName || 'Direct'
                const ingredient = ingredients.find(i => i.id === item.ingredient_id)

                if (!vendorGroups[vendorName]) {
                    vendorGroups[vendorName] = { name: vendorName, items: [], total: 0 }
                }
                vendorGroups[vendorName].items.push(item)
                vendorGroups[vendorName].total += item.quantity_to_order * (item.vendor_price || ingredient?.purchase_price || 0)
            })

            const vendorSummary = Object.values(vendorGroups)
                .map(g => `📦 ${g.name}: ${g.items.length} items ($${g.total.toFixed(2)})`)
                .join('\n')

            toast.success('Orders sent to vendors!', {
                description: vendorSummary,
                duration: 5000
            })

            // Clear the cart
            setAddedIds([])
            setRemovedIds([])
            setOrderQuantities({})
            setSelectedVendors({})

            router.refresh()
        },
        onError: (err) => toast.error(err.message)
    })

    // Compute total cost based on visible items and selected vendors
    const totalCost = visibleItems.reduce((acc, item) => {
        const qty = orderQuantities[item.id] || 0
        const vendorInfo = selectedVendors[item.id]
        const price = vendorInfo?.price || item.purchase_price
        return acc + (qty * price)
    }, 0)

    // Filter ingredients for the add dialog - now with vendor price info
    const searchResults = !itemSearch ? [] : ingredients
        .filter(i =>
            !visibleItems.find(v => v.id === i.id) &&
            i.name.toLowerCase().includes(itemSearch.toLowerCase())
        )
        .slice(0, 8) // Show more results
        .map(ingredient => {
            // Get all vendor options for this ingredient
            const vendorOptions = vendorProducts
                .filter(vp => vp.ingredient_id === ingredient.id)
                .map(vp => {
                    const vendor = vendors.find(v => v.id === vp.vendor_id)
                    return {
                        vendorId: vp.vendor_id,
                        vendorName: vendor?.name || 'Unknown',
                        price: vp.vendor_price,
                        unit: vp.unit,
                        packSize: vp.pack_size
                    }
                })
                .sort((a, b) => a.price - b.price) // Sort by price, cheapest first

            return {
                ...ingredient,
                vendorOptions,
                lowestPrice: vendorOptions.length > 0 ? vendorOptions[0].price : ingredient.purchase_price
            }
        })

    if (visibleItems.length === 0) {
        return (
            <div className="space-y-6">
                {/* Empty State with Add Button */}
                <Card className="bg-card border-border">
                    <CardContent className="flex flex-col items-center justify-center py-12 text-center">
                        <CheckCircle2 className="w-12 h-12 text-primary mb-4" />
                        <h3 className="text-xl font-bold text-foreground">All Par Levels Met</h3>
                        <p className="text-muted-foreground mt-2 mb-6">You have sufficient stock for all ingredients.</p>

                        <div className="relative">
                            <Button
                                variant="outline"
                                className="border-primary/20 text-primary hover:bg-primary/10"
                                onClick={() => setIsAddOpen(!isAddOpen)}
                            >
                                Manually Add Item
                            </Button>

                            {isAddOpen && (
                                <div className="absolute top-full mt-2 left-1/2 -translate-x-1/2 w-64 bg-sidebar border border-border rounded-xl shadow-2xl z-50 overflow-hidden">
                                    <div className="p-2 border-b border-border">
                                        <Input
                                            placeholder="Search ingredients..."
                                            className="h-8 bg-card border-none text-xs"
                                            value={itemSearch}
                                            onChange={e => setItemSearch(e.target.value)}
                                            autoFocus
                                        />
                                    </div>
                                    <div className="max-h-48 overflow-y-auto">
                                        {searchResults.map(i => (
                                            <button
                                                key={i.id}
                                                className="w-full text-left px-4 py-2 text-sm text-muted-foreground hover:bg-primary/10 hover:text-primary transition-colors"
                                                onClick={() => handleAddItem(i.id)}
                                            >
                                                {i.name}
                                            </button>
                                        ))}
                                        {searchResults.length === 0 && (
                                            <div className="p-4 text-xs text-muted-foreground text-center">No items found</div>
                                        )}
                                    </div>
                                </div>
                            )}
                        </div>
                    </CardContent>
                </Card>
            </div>
        )
    }

    return (
        <div className="space-y-6">
            <Card className="bg-card border-border">
                <CardHeader>
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                        <div>
                            <CardTitle className="text-foreground flex items-center gap-2">
                                <AlertTriangle className="w-5 h-5 text-amber-500" />
                                Needs Ordering ({visibleItems.length})
                            </CardTitle>
                        </div>
                        <div className="flex items-center gap-4">
                            {/* Add Item Popover */}
                            <div className="relative" ref={popupRef}>
                                <Button
                                    variant="outline"
                                    size="sm"
                                    className="border-border hover:bg-secondary"
                                    onClick={() => setIsAddOpen(!isAddOpen)}
                                >
                                    + Add Item
                                </Button>
                                {isAddOpen && (
                                    <div className="absolute top-full left-0 mt-2 w-96 bg-card border border-white/10 rounded-xl shadow-2xl z-[100] overflow-hidden ring-1 ring-black/50">
                                        <div className="p-3 border-b border-white/5 bg-sidebar/20">
                                            <Input
                                                placeholder="Search products..."
                                                className="h-9 bg-sidebar/40 border-white/10 text-foreground placeholder:text-muted-foreground focus:border-primary/50"
                                                value={itemSearch}
                                                onChange={e => setItemSearch(e.target.value)}
                                                autoFocus
                                            />
                                        </div>
                                        {vendors.length === 0 && (
                                            <div className="p-3 bg-amber-500/10 border-b border-amber-500/20 text-xs text-amber-500 flex items-center justify-between">
                                                <span>No vendors connected.</span>
                                                <Link href="/vendors" className="underline font-bold hover:text-amber-400">Connect Now</Link>
                                            </div>
                                        )}
                                        <div className="max-h-[400px] overflow-y-auto custom-scrollbar">
                                            {searchResults.map(item => (
                                                <div key={item.id} className="border-b border-white/5 last:border-0">
                                                    {/* Ingredient header */}
                                                    <div className="px-4 py-2 bg-sidebar/20">
                                                        <div className="font-bold text-foreground">{item.name}</div>
                                                        <div className="text-[10px] uppercase tracking-wider text-muted-foreground">{item.category || 'General'}</div>
                                                    </div>

                                                    {/* Vendor options */}
                                                    {item.vendorOptions.length > 0 ? (
                                                        <div className="divide-y divide-white/5">
                                                            {item.vendorOptions.map((vo, idx) => (
                                                                <button
                                                                    key={vo.vendorId}
                                                                    className="w-full text-left px-4 py-2 hover:bg-primary/10 transition-colors flex items-center justify-between group"
                                                                    onClick={() => handleAddItem(item.id, vo.vendorId, vo.vendorName, vo.price)}
                                                                >
                                                                    <div className="flex items-center gap-2">
                                                                        {idx === 0 && (
                                                                            <span className="text-[9px] font-bold px-1.5 py-0.5 rounded bg-primary/20 text-primary uppercase">
                                                                                Lowest
                                                                            </span>
                                                                        )}
                                                                        <span className="text-sm text-foreground group-hover:text-primary">
                                                                            {vo.vendorName}
                                                                        </span>
                                                                    </div>
                                                                    <div className="text-right">
                                                                        <div className={`font-bold ${idx === 0 ? 'text-primary' : 'text-muted-foreground'}`}>
                                                                            ${vo.price.toFixed(2)}
                                                                        </div>
                                                                        <div className="text-[10px] text-muted-foreground">
                                                                            /{vo.unit}
                                                                        </div>
                                                                    </div>
                                                                </button>
                                                            ))}
                                                        </div>
                                                    ) : (
                                                        <div className="px-4 py-2 flex items-center justify-between bg-sidebar/10">
                                                            <div className="text-sm text-muted-foreground">No prices yet</div>
                                                            <div className="flex gap-2">
                                                                <Button
                                                                    size="sm"
                                                                    variant="ghost"
                                                                    className="h-7 text-xs text-blue-400 hover:text-blue-300 hover:bg-blue-500/10"
                                                                    onClick={(e) => {
                                                                        e.stopPropagation()
                                                                        setManagePricesItem(item)
                                                                    }}
                                                                >
                                                                    Manage Prices
                                                                </Button>
                                                                <Button
                                                                    size="sm"
                                                                    variant="secondary"
                                                                    className="h-7 text-xs"
                                                                    onClick={() => handleAddItem(item.id)}
                                                                >
                                                                    Add Direct ($ {item.purchase_price})
                                                                </Button>
                                                            </div>
                                                        </div>
                                                    )}
                                                </div>
                                            ))}
                                            {searchResults.length === 0 && (
                                                <div className="p-8 text-sm text-muted-foreground text-center">
                                                    {itemSearch ? 'No matching products.' : 'Start typing to search...'}
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                )}
                            </div>

                            {/* Reset Button */}
                            <Button
                                variant="ghost"
                                size="sm"
                                onClick={handleReset}
                                className="text-muted-foreground hover:text-foreground"
                                title="Reset to default suggestions"
                            >
                                <RefreshCw className="w-4 h-4" />
                            </Button>

                            <div className="text-right pl-4 border-l border-border">
                                <div className="text-xs text-muted-foreground">Estimated Cost</div>
                                <div className="text-xl font-bold text-primary">${totalCost.toLocaleString()}</div>
                            </div>
                        </div>
                    </div>
                </CardHeader>
                <CardContent>
                    <Table>
                        <TableHeader>
                            <TableRow className="border-border hover:bg-transparent">
                                <TableHead className="text-muted-foreground">Ingredient</TableHead>
                                <TableHead className="text-muted-foreground">Vendor</TableHead>
                                <TableHead className="text-muted-foreground">Stock / Par</TableHead>
                                <TableHead className="text-muted-foreground w-[120px]">Order Qty</TableHead>
                                <TableHead className="text-muted-foreground text-right">Unit Price</TableHead>
                                <TableHead className="text-muted-foreground text-right">Line Total</TableHead>
                                <TableHead className="w-[50px]"></TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {visibleItems.map((item) => {
                                const qty = orderQuantities[item.id] || 0
                                const vendorInfo = selectedVendors[item.id]
                                const unitPrice = vendorInfo?.price || item.purchase_price
                                const lineTotal = qty * unitPrice

                                return (
                                    <TableRow key={item.id} className="border-border hover:bg-secondary/50 group">
                                        <TableCell className="font-medium text-foreground">
                                            {item.name}
                                            <div className="text-xs text-muted-foreground">{item.purchase_unit}</div>
                                        </TableCell>
                                        <TableCell>
                                            <Badge
                                                variant="outline"
                                                className={`text-xs ${vendorInfo?.vendorId ? 'border-primary/30 text-primary' : 'border-border text-muted-foreground'}`}
                                            >
                                                {vendorInfo?.vendorName || 'Direct'}
                                            </Badge>
                                        </TableCell>
                                        <TableCell>
                                            <div className="flex items-center gap-2">
                                                <span className={(item.current_stock ?? 0) < (item.par_level || 5) ? "text-red-400 font-bold" : "text-primary font-bold"}>
                                                    {item.current_stock ?? 0}
                                                </span>
                                                <span className="text-muted-foreground">/</span>
                                                <span className="text-foreground">{item.par_level || 5}</span>
                                            </div>
                                        </TableCell>
                                        <TableCell>
                                            <Input
                                                type="number"
                                                className="bg-sidebar border-border text-foreground w-20"
                                                value={qty}
                                                onChange={(e) => handleQuantityChange(item.id, e.target.value)}
                                            />
                                        </TableCell>
                                        <TableCell className="text-right text-muted-foreground">
                                            ${unitPrice.toFixed(2)}
                                        </TableCell>
                                        <TableCell className="text-right font-bold text-foreground">
                                            ${lineTotal.toLocaleString()}
                                        </TableCell>
                                        <TableCell>
                                            <button
                                                onClick={() => handleRemoveItem(item.id)}
                                                className="opacity-0 group-hover:opacity-100 p-2 text-muted-foreground hover:text-red-500 transition-all"
                                                title="Remove from order"
                                            >
                                                &times;
                                            </button>
                                        </TableCell>
                                    </TableRow>
                                )
                            })}
                        </TableBody>
                    </Table>
                </CardContent>
            </Card>

            <div className="flex justify-end">
                <Button
                    size="lg"
                    className="bg-primary hover:bg-primary text-foreground gap-2"
                    onClick={() => sendOrderMutation.mutate()}
                    disabled={sendOrderMutation.isPending}
                >
                    <Send className="w-4 h-4" />
                    {sendOrderMutation.isPending ? 'Sending...' : 'Send Orders'}
                </Button>
            </div>

            {/* Vendor Price Management Dialog */}
            <Dialog open={!!managePricesItem} onOpenChange={(open) => !open && setManagePricesItem(null)}>
                <DialogContent className="bg-card border-border text-foreground max-w-2xl">
                    {managePricesItem && (
                        <VendorPriceManager
                            ingredient={managePricesItem}
                            vendors={vendors}
                            existingPrices={vendorProducts.filter(vp => vp.ingredient_id === managePricesItem.id)}
                            onUpdate={() => {
                                router.refresh()
                            }}
                        />
                    )}
                </DialogContent>
            </Dialog>
        </div>
    )
}

'use client'

import { useState } from 'react'
import { Button } from '@/components/ui/button'
import { Flame, CreditCard, CheckCircle2 } from 'lucide-react'
import { fireOrder } from '@/lib/actions/pos'
import { toast } from 'sonner'
import { useRouter } from 'next/navigation'

interface ActionPanelProps {
    orderId: string
    status: 'draft' | 'fired' | 'paid'
    onPay: () => void
}

export default function ActionPanel({ orderId, status, onPay }: ActionPanelProps) {
    const [isLoading, setIsLoading] = useState(false)
    const router = useRouter()

    const handleFire = async () => {
        setIsLoading(true)
        try {
            await fireOrder(orderId)
            toast.success('Order fired to kitchen')
            router.refresh()
        } catch (error) {
            toast.error('Failed to fire order')
            console.error(error)
        } finally {
            setIsLoading(false)
        }
    }

    if (status === 'fired') {
        return (
            <Button
                size="lg"
                onClick={onPay}
                className="w-full h-20 bg-blue-600 hover:bg-blue-500 text-foreground text-xl font-black uppercase tracking-tighter rounded-2xl shadow-xl shadow-blue-900/20 active:scale-95 transition-all"
            >
                <div className="flex items-center gap-3">
                    <CreditCard className="w-6 h-6" />
                    Pay / Close Ticket
                </div>
            </Button>
        )
    }

    if (status === 'draft') {
        return (
            <Button
                size="lg"
                disabled={isLoading}
                onClick={handleFire}
                className="w-full h-20 bg-primary hover:bg-primary text-foreground text-xl font-black uppercase tracking-tighter rounded-2xl shadow-xl shadow-[#5A4820]/20 active:scale-95 transition-all group"
            >
                {isLoading ? (
                    <div className="flex items-center gap-3">
                        <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin" />
                        Syncing...
                    </div>
                ) : (
                    <div className="flex items-center gap-3">
                        <Flame className="w-6 h-6 group-hover:scale-110 transition-transform" />
                        Fire Order
                    </div>
                )}
            </Button>
        )
    }

    return (
        <Button disabled variant="outline" className="w-full h-20 text-muted-foreground font-bold uppercase tracking-widest bg-card border-white/10">
            Ticket Closed
        </Button>
    )
}

'use client'

import { useState, useEffect, useMemo, useRef } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { Users, Clock, Loader2, AlertCircle, Calendar, X, Bell } from 'lucide-react'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { cn } from '@/lib/utils'
import { Location, POSOrder, Reservation } from '@/lib/types/pos'
import LocationLedger from './location-ledger'

// Removed local Location interface

export default function FloorMap() {
    const router = useRouter()
    const [supabase] = useState(() => createClient())
    const [locations, setLocations] = useState<Location[]>([])
    const [view, setView] = useState<'floor' | 'rooms'>('floor')
    const [isEditMode, setIsEditMode] = useState(false)
    const [selectedLocation, setSelectedLocation] = useState<Location | null>(null)
    const [reservations, setReservations] = useState<Reservation[]>([])
    const [preOrders, setPreOrders] = useState<POSOrder[]>([])
    const [activeOrders, setActiveOrders] = useState<POSOrder[]>([])
    const [isLoading, setIsLoading] = useState(true)
    const [isSaving, setIsSaving] = useState(false)

    // Architect Logic
    const containerRef = useRef<HTMLDivElement>(null)
    const [interactionState, setInteractionState] = useState<{
        type: 'drag' | 'resize' | 'rotate'
        id: string
        startX: number
        startY: number
        initialX: number
        initialY: number
        initialW: number
        initialH: number
        initialR: number
        handle?: 'e' | 's' | 'se'
    } | null>(null)

    useEffect(() => {
        const handleGlobalMouseUp = () => {
            if (interactionState) handleInteractionEnd()
        }
        window.addEventListener('mouseup', handleGlobalMouseUp)
        return () => window.removeEventListener('mouseup', handleGlobalMouseUp)
    }, [interactionState])

    const handleInteractionStart = (e: React.MouseEvent | React.TouchEvent, location: Location, type: 'drag' | 'resize' | 'rotate', handle?: 'e' | 's' | 'se') => {
        if (!isEditMode) return
        e.stopPropagation()
        // Prevent scroll on touch devices when starting an interaction
        // if ('touches' in e) e.preventDefault() 

        const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX
        const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY

        setInteractionState({
            type,
            id: location.id,
            startX: clientX,
            startY: clientY,
            initialX: location.x_pos,
            initialY: location.y_pos,
            initialW: location.width || 0,
            initialH: location.height || 0,
            initialR: location.rotation || 0,
            handle
        })
    }

    const handleInteractionMove = (e: React.MouseEvent | React.TouchEvent) => {
        if (!interactionState || !containerRef.current) return

        const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX
        const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY

        const rect = containerRef.current.getBoundingClientRect()
        const deltaX = clientX - interactionState.startX
        const deltaY = clientY - interactionState.startY
        const deltaXPercent = (deltaX / rect.width) * 100
        const deltaYPercent = (deltaY / rect.height) * 100

        setLocations(prev => prev.map(l => {
            if (l.id !== interactionState.id) return l

            if (interactionState.type === 'drag') {
                return {
                    ...l,
                    x_pos: Math.max(0, Math.min(100, interactionState.initialX + deltaXPercent)),
                    y_pos: Math.max(0, Math.min(100, interactionState.initialY + deltaYPercent))
                }
            } else if (interactionState.type === 'resize') {
                const newW = interactionState.initialW + (interactionState.handle?.includes('e') ? deltaXPercent : 0)
                const newH = interactionState.initialH + (interactionState.handle?.includes('s') ? deltaYPercent : 0)
                return {
                    ...l,
                    width: Math.max(2, newW),
                    height: Math.max(2, newH)
                }
            } else if (interactionState.type === 'rotate') {
                return { ...l, rotation: (interactionState.initialR + deltaX) % 360 }
            }
            return l
        }))
    }

    const handleInteractionEnd = async () => {
        if (!interactionState) return
        const location = locations.find(l => l.id === interactionState.id)
        if (location) {
            const { error } = await supabase.from('locations').update({
                x_pos: location.x_pos,
                y_pos: location.y_pos,
                width: location.width,
                height: location.height,
                rotation: location.rotation
            }).eq('id', location.id)
            if (error) {
                console.error('Error updating location:', error.message, error.details, error.hint)
            }
        }
        setInteractionState(null)
    }

    useEffect(() => {
        const fetchData = async () => {
            // Fetch locations
            const { data: locData } = await supabase
                .from('locations')
                .select('*')
                .order('name')

            // Fetch upcoming reservations for today
            const today = new Date()
            today.setHours(0, 0, 0, 0)
            const tonight = new Date()
            tonight.setHours(23, 59, 59, 999)

            const { data: resData } = await supabase
                .from('reservations')
                .select('*')
                .gte('reservation_time', today.toISOString())
                .lte('reservation_time', tonight.toISOString())
                .eq('status', 'confirmed')

            // Fetch pending pre-orders for today
            const { data: orderData } = await supabase
                .from('orders')
                .select('*')
                .eq('is_preorder', true)
                .eq('preparation_status', 'pending')
                .gte('scheduled_for', today.toISOString())
                .lte('scheduled_for', tonight.toISOString())

            // Fetch active (non-delivered) orders
            const { data: activeOrderData } = await supabase
                .from('orders')
                .select('*')
                .neq('preparation_status', 'delivered')
                .neq('preparation_status', 'cancelled')

            if (locData) setLocations(locData)
            if (resData) setReservations(resData)
            if (activeOrderData) setActiveOrders(activeOrderData)
            if (orderData) setPreOrders(orderData)
            setIsLoading(false)
        }

        fetchData()

        const channel = supabase
            .channel('pos_floor_updates')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'locations' }, fetchData)
            .on('postgres_changes', { event: '*', schema: 'public', table: 'reservations' }, fetchData)
            .on('postgres_changes', { event: '*', schema: 'public', table: 'orders' }, fetchData)
            .subscribe()

        return () => { supabase.removeChannel(channel) }
    }, [supabase])

    const floorElements = useMemo(() => locations.filter(l => l.type !== 'room'), [locations])
    const rooms = useMemo(() => locations.filter(l => l.type === 'room'), [locations])



    const checkCollision = (x: number, y: number, w: number, h: number, existing: Location[]) => {
        // Assume rough percentages for conversion validity
        // AABB Collision Detection
        return existing.some(l => {
            // For existing items, use their width/height or defaults
            // Tables default to ~10% width/height if 0
            const lW = l.width || (l.type === 'table' ? 8 : 10)
            const lH = l.height || (l.type === 'table' ? 8 : 10)

            // Convert center-based coords (x,y) to top-left for easier math, or just use center difference
            // Our system uses center-center positioning: transform: translate(-50%, -50%)
            // So x,y is the center.

            const distanceX = Math.abs(x - l.x_pos)
            const distanceY = Math.abs(y - l.y_pos)

            const minDistanceX = (w + lW) / 2
            const minDistanceY = (h + lH) / 2

            return distanceX < minDistanceX && distanceY < minDistanceY
        })
    }

    const handleAddLocation = async (type: Location['type'] = 'table', w?: number, h?: number, subtype?: string) => {
        setIsSaving(true)
        const { data: { user } } = await supabase.auth.getUser()
        if (!user) {
            setIsSaving(false)
            return
        }


        const baseName = type === 'wall' ? 'Wall' : type === 'table' ? 'T' : type.charAt(0).toUpperCase() + type.slice(1)

        // Determine dimensions
        const width = w || (type === 'wall' ? 20 : type === 'table' ? 8 : 30)
        const height = h || (type === 'wall' ? 2 : type === 'table' ? 8 : 20)

        // Find free position
        let bestX = 50
        let bestY = 50

        // Scan grid
        let found = false
        for (let tryY = 10; tryY <= 90; tryY += 5) {
            for (let tryX = 10; tryX <= 90; tryX += 5) {
                if (!checkCollision(tryX, tryY, width, height, locations)) {
                    bestX = tryX
                    bestY = tryY
                    found = true
                    break
                }
            }
            if (found) break
        }

        // If grid full, add random jitter to center
        if (!found) {
            bestX = 50 + (Math.random() * 10 - 5)
            bestY = 50 + (Math.random() * 10 - 5)
        }

        const newLocation = {
            user_id: user.id,
            name: view === 'floor' ? `${baseName}-${locations.length + 1}` : `${100 + locations.length}`,
            type: view === 'floor' ? type : 'room', // Force 'room' if in room view for now
            status: 'available',
            x_pos: bestX,
            y_pos: bestY,
            width: w || (type === 'wall' ? 20 : type === 'table' ? 0 : 30), // 0 for table means use css class default
            height: h || (type === 'wall' ? 2 : type === 'table' ? 0 : 20),
            rotation: 0,
            capacity: type === 'table' ? 2 : 0,
            metadata: { color: 'neutral', subtype }
        }

        const { error } = await supabase.from('locations').insert(newLocation)
        if (error) console.error('Error adding location:', error)
        setIsSaving(false)
    }

    const handleDeleteLocation = async (id: string, e: React.MouseEvent) => {
        e.stopPropagation()
        if (!confirm('Are you sure you want to delete this location?')) return

        setIsSaving(true)
        const { error } = await supabase.from('locations').delete().eq('id', id)
        if (error) console.error('Error deleting location:', error)
        setIsSaving(false)
    }



